INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 3.414, 1, 62, "2030/01/01 14:59:59", 190805, -416.5, 1, 1000001, "カリン", 0.0, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2025/01/31 12:00:00", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 3.099, 1, 62, "2030/01/01 14:59:59", 190805, -416.5, 1, 1000002, "カリン", 0.0, "ミッションをクリアして、\n報酬をゲットしましょう！", "2025/01/31 12:00:00", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 2.801, 1, 63, "2030/01/01 14:59:59", 190805, -416.5, 1, 1000003, "カリン", 0.0, "受け取ることができる\n報酬があるようです\n確認してみてください", "2025/01/31 12:00:00", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 0.0, 2, 63, "2030/01/01 14:59:59", 190805, -416.5, 1, 1000004, "カリン", 0.0, "報酬がもらえますよ！\nチェックしてみてください", "2025/01/31 12:00:00", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 2.12, 2, 64, "2030/01/01 14:59:59", 190805, -363.0, 1, 1000005, "カリン", 0.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2025/01/31 12:00:00", 5);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 1.68, 1, 64, "2030/01/01 14:59:59", 190805, -363.0, 1, 1000006, "カリン", 0.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2025/01/31 12:00:00", 6);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 2.33, 2, 64, "2030/01/01 14:59:59", 190805, -363.0, 1, 1000007, "カリン", 0.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2025/01/31 12:00:00", 7);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7, 5.18, 3, 61, "2030/01/01 14:59:59", 133701, -285.0, 10201, 1020101, "ラビリスタ", -6.0, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", "2025/01/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 8.77, 1, 61, "2030/01/01 14:59:59", 133901, -285.0, 10201, 1020102, "クリスティーナ", -2.0, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", "2025/01/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 15.5, 6, 61, "2030/01/01 14:59:59", 133801, -285.0, 10201, 1020103, "ネネカ", 0.0, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", "2025/01/31 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5, 9.061, 2, 61, "2030/01/01 14:59:59", 134301, -285.0, 10202, 1020201, "ランファ", 0.0, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", "2025/02/28 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 7.699, 1, 61, "2030/01/01 14:59:59", 134401, -285.0, 10202, 1020202, "チカ", 0.0, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", "2025/02/28 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 8.595, 1, 61, "2030/01/01 14:59:59", 134601, -285.0, 10203, 1020301, "アオイ", 0.0, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", "2025/03/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 7.758, 1, 61, "2030/01/01 14:59:59", 134501, -285.0, 10203, 1020302, "クローチェ", 0.0, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", "2025/03/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6, 7.0, 2, 61, "2030/01/01 14:59:59", 132302, -285.0, 10204, 1020401, "ルイズマリー", 0.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", "2025/04/30 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 7.904, 1, 61, "2030/01/01 14:59:59", 132402, -285.0, 10204, 1020402, "イロハ", 0.0, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", "2025/04/30 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 8.487, 4, 61, "2030/01/01 14:59:59", 132502, -285.0, 10204, 1020403, "ソノ", 0.0, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", "2025/04/30 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 8.763, 1, 61, "2030/01/01 14:59:59", 134901, -285.0, 10205, 1020502, "カノン", 0.0, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", "2025/05/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 6.417, 1, 61, "2030/01/01 14:59:59", 134801, -285.0, 10205, 1020503, "ツムギ", 0.0, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", "2025/05/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7, 10.335, 3, 61, "2030/01/01 14:59:59", 135001, -285.0, 10206, 1020601, "エリス", 0.0, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", "2025/06/30 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (4, 6.281, 2, 61, "2030/01/01 14:59:59", 135101, -285.0, 10206, 1020602, "シェフィ", 0.0, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", "2025/06/30 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 12.244, 1, 61, "2030/01/01 14:59:59", 135201, -285.0, 10206, 1020603, "プレシア", 0.0, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", "2025/06/30 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8, 6.339, 2, 61, "2030/01/01 14:59:59", 135301, -285.0, 10207, 1020701, "クリア", 0.0, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", "2025/07/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (9, 8.184, 7, 61, "2030/01/01 14:59:59", 135401, -285.0, 10207, 1020702, "アネモネ", 0.0, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", "2025/07/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 3.906, 9, 61, "2030/01/01 14:59:59", 129101, -285.0, 10208, 1020801, "アイラ", 0.0, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", "2025/08/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 14.465, 1, 61, "2030/01/01 14:59:59", 129201, -285.0, 10208, 1020802, "シナツ", 0.0, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", "2025/08/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 8.662, 4, 61, "2030/01/01 14:59:59", 100101, -285.0, 10208, 1020803, "ヒヨリ", 0.0, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", "2025/08/31 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 10.915, 1, 61, "2030/01/01 14:59:59", 100301, -285.0, 10208, 1020804, "レイ", 0.0, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", "2025/08/31 12:00:00", 401);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7, 6.042, 1, 61, "2030/01/01 14:59:59", 135802, -285.0, 10209, 1020901, "ユキノ", 0.0, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", "2025/09/30 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 9.402, 4, 61, "2030/01/01 14:59:59", 135903, -285.0, 10209, 1020902, "サツキ", 0.0, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", "2025/09/30 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 8.16, 8, 61, "2030/01/01 14:59:59", 136902, -285.0, 10209, 1020903, "ルルィ", 0.0, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", "2025/09/30 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 5.0, 3, 61, "2030/01/01 14:59:59", 137401, -285.0, 10210, 1021001, "カスミ", 0.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", "2025/10/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 8.12, 4, 61, "2030/01/01 14:59:59", 136001, -285.0, 10210, 1021002, "アラクネ", 0.0, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", "2025/10/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 6.386, 4, 61, "2030/01/01 14:59:59", 136202, -285.0, 10210, 1021003, "ナーナ", 0.0, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", "2025/10/31 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (4, 7.438, 3, 61, "2030/01/01 14:59:59", 136402, -285.0, 10211, 1021101, "ユイ", 0.0, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", "2025/11/30 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5, 8.35, 1, 61, "2030/01/01 14:59:59", 136302, -285.0, 10211, 1021102, "ミソラ", 0.0, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", "2025/11/30 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 5.0, 1, 61, "2030/01/01 14:59:59", 136501, -285.0, 10212, 1021201, "シズル", 0.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", "2025/12/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 5.25, 1, 61, "2030/01/01 14:59:59", 137902, -285.0, 10212, 1021202, "リノ", 0.0, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", "2025/12/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 7.5, 1, 61, "2030/01/01 14:59:59", 106801, -285.0, 10212, 1021203, "ラビリスタ", 0.0, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", "2025/12/31 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 8.204, 1, 61, "2030/01/01 14:59:59", 126501, -285.0, 10213, 1021301, "ライラエル", 0.0, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", "2026/01/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 7.176, 1, 61, "2030/01/01 14:59:59", 129701, -285.0, 10213, 1021302, "ネフィ＝ネラ", 0.0, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", "2026/01/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5, 8.602, 1, 61, "2030/01/01 14:59:59", 133101, -285.0, 10213, 1021303, "ヴァイオレット", 0.0, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", "2026/01/31 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 10.14, 1, 61, "2030/01/01 14:59:59", 138101, -285.0, 10213, 1021304, "ライラエル", 0.0, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", "2026/02/06 12:00:00", 102);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7, 10.152, 1, 61, "2030/01/01 14:59:59", 138201, -285.0, 10213, 1021305, "ネフィ＝ネラ", 0.0, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", "2026/02/06 12:00:00", 202);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 9.688, 4, 61, "2030/01/01 14:59:59", 138001, -285.0, 10213, 1021306, "ヴァイオレット", 0.0, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", "2026/02/06 12:00:00", 302);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 5.928, 2, 61, "2030/01/01 14:59:59", 138301, -285.0, 10213, 1021307, "ペコリーヌ", 0.0, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", "2026/02/12 12:00:00", 401);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 9.19, 4, 61, "2030/01/01 14:59:59", 138702, -285.0, 10214, 1021401, "ワカナ", 0.0, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", "2026/02/28 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 8.724, 1, 61, "2030/01/01 14:59:59", 138802, -285.0, 10214, 1021402, "シオリ", 0.0, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", "2026/02/28 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 7.758, 4, 61, "2030/01/01 14:59:59", 138902, -285.0, 10215, 1021501, "グレイス", 0.0, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", "2026/03/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (4, 6.375, 6, 61, "2030/01/01 14:59:59", 139002, -285.0, 10215, 1021502, "キョウカ", 0.0, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", "2026/03/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 6.173, 6, 61, "2030/01/01 14:59:59", 136902, -285.0, 10215, 1021503, "ルルィ", 0.0, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", "2026/03/31 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 4.202, 6, 61, "2030/01/01 14:59:59", 139202, -285.0, 10216, 1021601, "ミホ", 0.0, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", "2026/04/30 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 2.842, 6, 61, "2030/01/01 14:59:59", 139302, -285.0, 10216, 1021602, "マホ", 0.0, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", "2026/04/30 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 4.598, 4, 61, "2030/01/01 14:59:59", 139402, -285.0, 10216, 1021603, "エリカ", 0.0, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", "2026/04/30 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 6.533, 4, 61, "2030/01/01 14:59:59", 125802, -285.0, 10217, 1021701, "リリ", 0.0, "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", "2026/05/31 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 5.0, 3, 61, "2030/01/01 14:59:59", 126102, -285.0, 10217, 1021702, "プレシア", 0.0, "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", "2026/05/31 12:00:00", 301);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (4, 5.214, 3, 61, "2030/01/01 14:59:59", 126002, -285.0, 10217, 1021703, "クリア", 0.0, "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", "2026/05/31 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 8.781, 1, 61, "2030/01/01 14:59:59", 139501, -285.0, 10217, 1021704, "リリ", 0.0, "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", "2026/05/31 12:00:00", 102);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 6.529, 2, 61, "2030/01/01 14:59:59", 139601, -285.0, 10217, 1021705, "クリア", 0.0, "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", "2026/05/31 12:00:00", 202);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 3.195, 3, 61, "2030/01/01 14:59:59", 139701, -285.0, 10217, 1021706, "プレシア", 0.0, "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", "2026/05/31 12:00:00", 302);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 12.43, 2, 61, "2030/01/01 14:59:59", 139902, -285.0, 10218, 1021801, "ルイズマリー", 0.0, "ダーリンと一緒に南の島で\nリゾート開発なんて夢みたい♪\nああ…幸せ、最高の夏だわ…\n触れたら爆発さえしなければ～…っ", "2026/06/30 12:00:00", 101);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3, 6.35, 2, 61, "2030/01/01 14:59:59", 140001, -285.0, 10218, 1021802, "クレジッタ", 0.0, "青い空、白い雲…無人島リゾートで\n大儲けですわ～♪　こらこらそこ、\nイチャついてるんじゃないですのよ\n触れたらドカンですわよ、ドカン！", "2026/06/30 12:00:00", 201);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 3.414, 1, 62, "2030/01/01 14:59:59", 190801, -416.5, 2, 2000001, "カリン", 0.0, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2026/04/10 12:00:00", 1);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 3.099, 1, 62, "2030/01/01 14:59:59", 190801, -416.5, 2, 2000002, "カリン", 0.0, "ミッションをクリアして、\n報酬をゲットしましょう！", "2026/04/10 12:00:00", 2);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 2.801, 1, 63, "2030/01/01 14:59:59", 190801, -416.5, 2, 2000003, "カリン", 0.0, "受け取ることができる\n報酬があるようです\n確認してみてください", "2026/04/10 12:00:00", 3);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 0.0, 2, 63, "2030/01/01 14:59:59", 190801, -416.5, 2, 2000004, "カリン", 0.0, "報酬がもらえますよ！\nチェックしてみてください", "2026/04/10 12:00:00", 4);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 2.12, 2, 64, "2030/01/01 14:59:59", 190801, -363.0, 2, 2000005, "カリン", 0.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2026/04/10 12:00:00", 5);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2, 1.68, 1, 64, "2030/01/01 14:59:59", 190801, -363.0, 2, 2000006, "カリン", 0.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2026/04/10 12:00:00", 6);
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1, 2.33, 2, 64, "2030/01/01 14:59:59", 190801, -363.0, 2, 2000007, "カリン", 0.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2026/04/10 12:00:00", 7);
